      display: flex;
      flex-direction: column;
      align-items: center;
      gap: 1rem;
      text-align: center;
    }

    .error-detail {
      color: var(--p-text-muted-color);
      margin: 0;
    }

    .entity-header {
      display: flex;
      align-items: center;
      gap: 1rem;
    }

    .entity-title {
      display: flex;
      align-items: center;
      gap: 0.75rem;
    }

    .entity-title h1 {
      margin: 0;
      font-size: 1.5rem;
      font-weight: 600;
      color: var(--p-text-color);
    }

    .skeleton-header {
      display: flex;
      align-items: center;
      gap: 1rem;
    }

    .skeleton-title {
      display: flex;
      align-items: center;
      gap: 0.75rem;
    }

    .info-section {
      display: grid;
      grid-template-columns: 1fr 1fr;
      gap: 1.25rem;
    }

    .info-section .full-width {
      grid-column: 1 / -1;
    }

    .field {
      display: flex;
      flex-direction: column;
      gap: 0.375rem;
    }

    .field.full-width {
      grid-column: 1 / -1;
    }

    .action-buttons {
      display: flex;
      gap: 0.75rem;
    }
  `,
})
export class Detail {
  private route = inject(ActivatedRoute);
  private router = inject(Router);
  private projectService = inject(ProjectService);

  project = this.projectService.projectById(
    Number(this.route.snapshot.paramMap.get('id'))
  );

  goBack() {
    this.router.navigate(['/list']);
  }
}

