import { Component, input, model } from '@angular/core';
import { FormsModule } from '@angular/forms';
import { InputText } from 'primeng/inputtext';

/**
 * Atom: Thin wrapper around PrimeNG InputText.
 *
 * Uses model() instead of input() for the value because the user types into
 * the field — both parent and child need to read and write the same value.
 * This enables two-way binding: [(value)]="searchTerm".
 */
@Component({
  selector: 'ds-input',
  imports: [InputText, FormsModule],
  template: `
    <input pInputText [(ngModel)]="value" [placeholder]="placeholder()" />
  `,
})
export class DsInput {
  value = model<string>('');
  placeholder = input<string>('');
}

import { Component, input, output } from '@angular/core';
import { Project } from '../../../models';
import { DsEmptyState } from '../../atoms/empty-state/empty-state';
import { DsButton } from '../../atoms/button/button';
import { DsTag } from '../../atoms/tag/tag';
import { Skeleton } from 'primeng/skeleton';
import { Message } from 'primeng/message';
import { Card } from 'primeng/card';
import { Avatar } from 'primeng/avatar';

@Component({
  selector: 'ds-project-card-grid',
  imports: [DsEmptyState, DsButton, DsTag, Skeleton, Message, Card, Avatar],
  templateUrl: './project-card-grid.html',
  styleUrl: './project-card-grid.scss',
})
export class DsProjectCardGrid {
  projects = input<Project[]>([]);
  isLoading = input(false);
  error = input<string | null>(null);
  projectSelected = output<Project>();
